import styles from "../_styles/menuContainer.module.css"
import clsx from 'clsx';

export default function MenuContainer({ menuOptions, isOpen }) {
    const optionsList = menuOptions.map((option) =>
        <button key={option.id} className={styles.option}>
            {option.title}
        </button>
    )
    return (
        <div className={clsx(styles["menu-container"])}>
            <div className={styles["menu-list"]}>{optionsList} </div>
        </div>
    );
}